                if 'completed' in context.lower() and '2022' in context:
                    # Try to find exact completion date
                    date_match = re.search(r'(\w+\s+2022)', context, re.IGNORECASE)
                    if date_match:
                        park_projects.append({
                            'name': line,
                            'date': date_match.group(1)
                        })

# Remove duplicates
